    def __init__(self, years):
        # years — список/массив годов строками, например ["2019","2020",...,"2025"]
        # используется дальше в decor(): фильтрация итоговой таблицы по нужным годам
        self.years = years


    def currency(self):
        """
        Тянет курс JPY->USD из BIS (WS_XRU), помесячно.
        Нужен, чтобы перевести "Значение (стоимость)" из JPY в USD в decor().
        Возвращает DataFrame с колонками:
        - Отчетный период (в формате "01.MM.YYYY")
        - Курс (число)
        - Единицы стоимости (валюта серии, ожидаемо JPY)
        """
        # Код валюты по BIS для японской иены
        curr = "JP.JPY"
        end_period = datetime.today().strftime("%Y-%m")
        url = (
            f"https://stats.bis.org/api/v1/data/BIS,WS_XRU,1.0/M.{curr}.A/all"
            f"?startPeriod=2019-01&endPeriod={end_period}"
        )
        print(url)

        # Делаем запрос на BIS API
        resp = requests.get(url)
        resp.raise_for_status()  # если 4xx/5xx — сразу исключение

        # BIS отдает SDMX-XML — парсим XML
        root = ET.fromstring(resp.content)

        # В SDMX структура такая, что данные лежат в Series -> Obs
        series = root.find('.//Series')

        # Атрибут валюты серии, чтобы потом мерджить по ["Отчетный период", "Единицы стоимости"]
        currency = series.get('CURRENCY')

        # Собираем наблюдения по месяцам
        records = []
        for obs in series.findall('Obs'):
            period = obs.get('TIME_PERIOD')          # "YYYY-MM"
            value = float(obs.get('OBS_VALUE'))      # курс как число
            records.append({
                'Отчетный период': period,
                'Курс': value,
                'Единицы стоимости': currency
            })

        # В df приводим период к формату проекта "01.MM.YYYY"
        df = pd.DataFrame(records)
        df['Отчетный период'] = (
            "01." + df['Отчетный период'].str[-2:] + '.' + df['Отчетный период'].str[:4]
        )
        return df


    def decor(self):
        """
        Оформление итоговой таблицы:
        1) читает сырой CSV, который предварительно собран parse()
        2) добавляет стандартные поля (страны, HS-коды, направления, единицы)
        3) переводит стоимость из JPY в USD через currency()
        4) фильтрует по нужным годам self.years
        5) возвращает DataFrame в унифицированной схеме
        """

        # Сырье после parse(): там строки по HS8/год/месяц и метрики
        data = pd.read_csv(Japan.japan_params["CSV_PATH_JAPAN"])

        # Приводим month/year к строкам для сборки даты "01.MM.YYYY"
        data["month"] = data['month'].astype(str)
        data["year"] = data['year'].astype(str)

        # Собираем отчетный период под общий формат проекта
        data['Отчетный период'] = "01." + data['month'].str.zfill(2) + '.' + data["year"]

        # Фиксируем страны
        data["Страна-партнер"] = "Россия"
        data["Исходная страна"] = "Япония"

        # Достаём HS-иерархию из HS8-кода "code"
        # (в parse() code приходит из @cat01)
        data["Код товара (2 знака)"] = data["code"].str[:2]
        data["Код товара (4 знака)"] = data["code"].str[:4]
        data["Код товара (6 знаков)"] = data["code"].str[:6]
        data["Код товара (8 знаков)"] = data["code"].str[:8]

        # unit1/quantity1 — условно "доп. единица" (ДЭИ) и её количество
        data["ДЭИ, описание"] = data["unit1"]
        data["Дополнительная единица измерения (ДЭИ)"] = data["quantity1"]

        # Валюта источника до конвертации
        data["Единицы стоимости"] = "JPY"

        # unit2/quantity2 — основная единица объема/массы и ее количество
        data["Единица объема"] = data["unit2"]

        # value_month по коду приходит как "тыс. JPY"
        data["Значение (стоимость)"] = data["value_month"].astype(float) * 1000

        # quantity2 — основное количество (масса/объем), как есть из источника
        data["Значение (масса)"] = data["quantity2"].astype(float)

        # Иногда quantity1 может быть NaN -> заменяем на 0 (чтобы спокойно приводить к float)
        data["Дополнительная единица измерения (ДЭИ)"] = (
            data["Дополнительная единица измерения (ДЭИ)"].fillna(0)
        )

        # Приводим направление в русский формат
        data["Направление"] = data["Направление"].replace({"import": "Импорт", "export": "Экспорт"})

        # Сортируем по убыванию года/месяца и с "Экспорт/Импорт" стабильным порядком
        data = data.sort_values(
            by=['year', 'month', 'Направление'],
            ascending=[False, False, True],
            key=lambda col: col.astype(int) if col.name in ['year', 'month'] else col,
            ignore_index=True
        )

        # HS2 должен быть двузначным (на случай если "1" вместо "01")
        data["Код товара (2 знака)"] = data["Код товара (2 знака)"].astype(str).str.zfill(2)

        # HS10 в источнике нет
        data["Код товара (10 знаков)"] = np.nan

        # Приводим ключевые метрики к float (иначе будут проблемы при расчетах/фильтрах)
        data["Значение (стоимость)"] = data["Значение (стоимость)"].astype(float)
        data["Значение (масса)"] = data["Значение (масса)"].astype(float)
        data["Дополнительная единица измерения (ДЭИ)"] = data["Дополнительная единица измерения (ДЭИ)"].astype(float)

        # Поле под "стоимость по доп. единице" (если бы было) — здесь нет
        data["Значение (стоимость) - ДЭИ"] = np.nan

        # Оставляем строго нужный порядок колонок
        data = data[[
            'Отчетный период', 'Исходная страна', 'Страна-партнер', 'Направление',
            'Код товара (2 знака)', 'Код товара (4 знака)', 'Код товара (6 знаков)',
            'Код товара (8 знаков)', 'Код товара (10 знаков)',
            'Значение (стоимость)', 'Единицы стоимости',
            'Значение (масса)', 'Единица объема',
            'Дополнительная единица измерения (ДЭИ)', 'ДЭИ, описание',
            "Значение (стоимость) - ДЭИ"
        ]]

        # Подтягиваем курсы (JPY->USD) и конвертируем стоимость
        df = self.currency()

        # Мерджим по отчетному периоду и валюте (JPY)
        data = pd.merge(data, df, how='left', on=["Отчетный период", "Единицы стоимости"])

        # Конвертация: стоимость в USD = стоимость в JPY / курс
        data.loc[data["Единицы стоимости"] != "USD", "Значение (стоимость)"] = (
            data["Значение (стоимость)"] / data["Курс"]
        )

        # Курс больше не нужен
        data = data.drop(columns="Курс")
        # Считаем, что теперь все в USD
        data["Единицы стоимости"] = "USD"
        # Фильтруем по нужным годам (self.years)
        # Сейчас это делается по строке "Отчетный период" (последние 4 символа)
        data = data[data["Отчетный период"].str[-4:].isin(self.years)]
        # Убираем технический "00" (как правило это "Итого/неопределено")
        data = data[data["Код товара (2 знака)"] != "00"]
        # Финально переводим отчетный период в datetime
        data['Отчетный период'] = pd.to_datetime(data['Отчетный период'], format='%d.%m.%Y')
        return data


    def parse(self) -> pd.DataFrame:
        """
        Основной сбор данных из японского API:
        - проходит по направлениям export/import
        - по батчам HS8 (по 100 кодов) дергает API
        - парсит JSON, раскладывает в табличный вид
        - пишет в временный CSV Japan.japan_params["CSV_PATH_JAPAN"]
        - потом вызывает decor() для стандартизации и конвертации валюты
        """

        first_iter = True
        # Если от прошлого запуска остался CSV — удаляем
        if os.path.exists(Japan.japan_params["CSV_PATH_JAPAN"]):
            os.remove(Japan.japan_params["CSV_PATH_JAPAN"])

        # Два направления: экспорт и импорт
        for direct in ["export", "import"]:

            # hs8_batch_{direct} — список батчей HS8 кодов
            # total считается странно/хрупко (берется [0] и делится на 100),
            # но на tqdm это влияет только на прогресс-бар.
            for batch in tqdm(
                Japan.japan_params[f"hs8_batch_{direct}"],
                total=len(Japan.japan_params[f"hs8_batch_{direct}"][0]) * len(Japan.japan_params[f"hs8_batch_{direct}"]) // 100,
                desc=f"Спаршено HS8 (батчей по 100 шт) - {direct}",
                unit='batch'
            ):
                # Кодируем список HS8 для URL (через %2C = запятая)
                api_hs8_batch = '%2C'.join(batch)

                # Собираем URL из двух частей: prefix + hs_batch + suffix
                api_link = (
                    Japan.japan_params[f"url_1_{direct}"]
                    + api_hs8_batch
                    + Japan.japan_params[f"url_2_{direct}"]
                )

                # Запрос
                resp = requests.get(url=api_link)
                api = resp.json()

                # Если по батчу нет данных — пропускаем
                if api['GET_STATS_DATA']['RESULT']['ERROR_MSG'] == 'The process has been successfully completed, but there was no data.':
                    continue

                # VALUE — массив наблюдений
                records = api['GET_STATS_DATA']['STATISTICAL_DATA']['DATA_INF']['VALUE']

                # В raw: каждая строка — одно наблюдение: код товара, код показателя (cat02), время и значение
                raw = pd.DataFrame(records)

                # Приводим названия к человеческим
                raw = raw.rename(columns={
                    '@cat01': 'code',   # HS код
                    '@cat02': 'cat02',  # “тип измерения”/серия (unit/qty/value по месяцам)
                    '@time': 'time',    # время
                    '$': 'value',       # значение
                    '@unit': 'unit'     # единица
                })

                # Переводим данные в “wide” формат:
                # строки: (HS code, time), колонки: cat02
                # так удобнее потом вытаскивать qty/value по каждому месяцу
                pivot = raw.pivot_table(
                    index=['code', 'time'],
                    columns='cat02',
                    values='value',
                    aggfunc='first'
                ).reset_index()

                # Собираем “помесячные” строки вручную:
                # каждый pivot-row содержит годовые серии с закодированными cat02:
                #   unit1 = row['100'], unit2 = row['110']
                #   дальше qty/value кодируются формулой: 150 + (month-1)*30 (+10 / +20)
                out_rows = []
                for _, row in pivot.iterrows():
                    year = row['time'][:4]  # берем год

                    for month_idx in range(1, 13):
                        # КОДЫ ВАЖНЫ (зашиты под конкретную структуру японского API):
                        # qty1_code: базовый код количества (месяц)
                        # qty2_code: вторая метрика количества (месяц)
                        # val_code:  стоимость (месяц)
                        qty1_code = 150 + (month_idx - 1) * 30
                        qty2_code = qty1_code + 10
                        val_code  = qty1_code + 20

                        out_rows.append({
                            'year': year,
                            'Направление': direct,
                            'month': month_idx,
                            'code': row['code'],

                            # единицы измерения (как их кодирует API)
                            'unit1': row.get('100'),
                            'unit2': row.get('110'),

                            # значения по месяцам — если нет, ставим 0
                            'quantity1': row.get(str(qty1_code), 0),
                            'quantity2': row.get(str(qty2_code), 0),
                            'value_month': row.get(str(val_code), 0),
                        })

                df = pd.DataFrame(out_rows, columns=[
                    'year', 'Направление', 'month', 'code', 'unit1', 'unit2', 'quantity1', 'quantity2', 'value_month'
                ])

                # Убираем строки с нулевой стоимостью
                df = df[df["value_month"] != '0']

                # Пишем в CSV (накапливаем батчи)
                df.to_csv(
                    Japan.japan_params["CSV_PATH_JAPAN"],
                    mode="a",
                    index=False,
                    header=first_iter,
                    encoding="utf-8-sig",
                )
                first_iter = False

        print("Парсинг успешно завершен. Перехожу к составлению и оформлению итоговой таблицы.")

        # Приводим к финальному формату + конвертим валюту
        data = self.decor()
        # Чистим временный CSV
        if os.path.exists(Japan.japan_params["CSV_PATH_JAPAN"]):
            os.remove(Japan.japan_params["CSV_PATH_JAPAN"])
        return data






